import sys

class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class Solution:
    def printList(self, head: 'Node') -> None:
        current = head
        while current:
            print(current.data)
            current = current.next

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        head = None
        tail = None
        for _ in range(n):
            data = int(next(it))
            node = Node(data)
            if not head:
                head = node
                tail = node
            else:
                tail.next = node
                tail = node
        next(it)  # Consume -1
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    sol.printList(head)

